1	import { useState, useEffect } from "react";
2	import { View, Text, Input, Picker } from "@tarojs/components";
3	import { useDidShow } from "@tarojs/taro";
4	import { apiFetch, PRESET_DOMAINS } from "../../lib";
5	import "./index.scss";
6	
7	interface Habit {
8	  id: string;
9	  title: string;
10	  description: string | null;
11	  domainId: string;
12	  unit: string;
13	  targetValue: number;
14	  frequency: string;
15	  isActive: boolean;
16	}
17	
18	export default function HabitsPage() {
19	  const [habits, setHabits] = useState<Habit[]>([]);
20	  const [loading, setLoading] = useState(true);
21	  const [showForm, setShowForm] = useState(false);
22	  const [editId, setEditId] = useState<string | null>(null);
23	  const [form, setForm] = useState({
24	    title: "", description: "", domainIdx: 0, unit: "次",
25	    targetValue: 1, frequency: "daily",
26	  });
27	
28	  useDidShow(() => { fetchHabits(); });
29	
30	  async function fetchHabits() {
31	    setHabits(await apiFetch("/api/habits"));
32	    setLoading(false);
33	  }
34	
35	  function openNew() {
36	    setEditId(null);
37	    setForm({ title: "", description: "", domainIdx: 0, unit: "次", targetValue: 1, frequency: "daily" });
38	    setShowForm(true);
39	  }
40	
41	  function openEdit(h: Habit) {
42	    setEditId(h.id);
43	    setForm({ title: h.title, description: h.description || "", domainIdx: PRESET_DOMAINS.findIndex(d => d.name === h.domainId), unit: h.unit, targetValue: h.targetValue, frequency: h.frequency });
44	    setShowForm(true);
45	  }
46	
47	  async function handleSave() {
48	    const body = { ...form, domainId: PRESET_DOMAINS[form.domainIdx].name };
49	    if (editId) {
50	      await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: editId, ...body }) });
51	    } else {
52	      await apiFetch("/api/habits", { method: "POST", body: JSON.stringify(body) });
53	    }
54	    setShowForm(false);
55	    fetchHabits();
56	  }
57	
58	  async function deleteHabit(id: string) {
59	    await apiFetch("/api/habits", { method: "DELETE", body: JSON.stringify({ id }) });
60	    fetchHabits();
61	  }
62	
63	  async function toggleActive(id: string, current: boolean) {
64	    await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id, isActive: !current }) });
65	    fetchHabits();
66	  }
67	
68	  return (
69	    <View className="page">
70	      <View className="page-header">
71	        <View>
72	          <Text className="page-title">习惯管理</Text>
73	          <Text className="page-subtitle">管理你的每日修炼清单</Text>
74	        </View>
75	        <View className="add-btn" onClick={openNew}><Text>+</Text></View>
76	      </View>
77	
78	      {PRESET_DOMAINS.map((domain) => {
79	        const domainHabits = habits.filter((h) => h.domainId === domain.name);
80	        return (
81	          <View key={domain.name}>
82	            <Text className="domain-title">{domain.icon} {domain.name}</Text>
83	            {domainHabits.map((habit) => (
84	              <View key={habit.id} className={`habit-card ${!habit.isActive ? "inactive" : ""}`}>
85	                <View className="habit-info">
86	                  <Text className="habit-name">{habit.title}</Text>
87	                  {habit.description && <Text className="habit-desc">{habit.description}</Text>}
88	                  <View className="habit-meta">
89	                    <Text>{habit.frequency === "daily" ? "每日" : habit.frequency}</Text>
90	                    <Text> · </Text>
91	                    <Text>目标 {habit.targetValue}{habit.unit}</Text>
92	                  </View>
93	                </View>
94	                <View className="habit-actions">
95	                  <Text className="action-btn" onClick={() => toggleActive(habit.id, habit.isActive)}>
96	                    {habit.isActive ? "停用" : "启用"}
97	                  </Text>
98	                  <Text className="action-btn" onClick={() => openEdit(habit)}>编辑</Text>
99	                  <Text className="action-btn danger" onClick={() => deleteHabit(habit.id)}>删除</Text>
100	                </View>
101	              </View>
102	            ))}
103	          </View>
104	        );
105	      })}
106	
107	      {!loading && habits.length === 0 && (
108	        <View className="empty"><Text>还没有习惯，点右上角 + 开始</Text></View>
109	      )}
110	
111	      {/* Form Modal */}
112	      {showForm && (
113	        <View className="modal-mask" onClick={() => setShowForm(false)}>
114	          <View className="modal" onClick={(e) => e.stopPropagation()}>
115	            <Text className="modal-title">{editId ? "编辑习惯" : "新增习惯"}</Text>
116	
117	            <View className="form-group">
118	              <Text className="form-label">名称</Text>
119	              <Input className="form-input" placeholder="如：晨跑30分钟" value={form.title} onInput={(e) => setForm({ ...form, title: e.detail.value })} />
120	            </View>
121	
122	            <View className="form-group">
123	              <Text className="form-label">描述</Text>
124	              <Input className="form-input" placeholder="具体怎么做" value={form.description} onInput={(e) => setForm({ ...form, description: e.detail.value })} />
125	            </View>
126	
127	            <View className="form-row">
128	              <View className="form-group flex-1">
129	                <Text className="form-label">领域</Text>
130	                <Picker mode="selector" range={PRESET_DOMAINS.map(d => d.icon + " " + d.name)} value={form.domainIdx} onChange={(e) => setForm({ ...form, domainIdx: +e.detail.value })}>
131	                  <View className="form-picker">{PRESET_DOMAINS[form.domainIdx].icon} {PRESET_DOMAINS[form.domainIdx].name}</View>
132	                </Picker>
133	              </View>
134	              <View className="form-group flex-1">
135	                <Text className="form-label">频率</Text>
136	                <Picker mode="selector" range={["每日", "每周", "工作日"]} value={form.frequency === "daily" ? 0 : form.frequency === "weekly" ? 1 : 2} onChange={(e) => setForm({ ...form, frequency: ["daily","weekly","weekday"][+e.detail.value] })}>
137	                  <View className="form-picker">{form.frequency === "daily" ? "每日" : form.frequency === "weekly" ? "每周" : "工作日"}</View>
138	                </Picker>
139	              </View>
140	            </View>
141	
142	            <View className="form-row">
143	              <View className="form-group flex-1">
144	                <Text className="form-label">目标值</Text>
145	                <Input className="form-input" type="number" value={String(form.targetValue)} onInput={(e) => setForm({ ...form, targetValue: +e.detail.value || 1 })} />
146	              </View>
147	              <View className="form-group flex-1">
148	                <Text className="form-label">单位</Text>
149	                <Input className="form-input" placeholder="次/分钟/页" value={form.unit} onInput={(e) => setForm({ ...form, unit: e.detail.value })} />
150	              </View>
151	            </View>
152	
153	            <View className="form-buttons">
154	              <View className="btn-cancel" onClick={() => setShowForm(false)}><Text>取消</Text></View>
155	              <View className="btn-save" onClick={handleSave}><Text>{editId ? "保存" : "添加"}</Text></View>
156	            </View>
157	          </View>
158	        </View>
159	      )}
160	    </View>
161	  );
162	}
